    /// Lazily populate the reflection hashes (`%b`, `%stryke::builtins`, etc.)
    /// on first access. This avoids building ~12k hash entries on startup for
    /// one-liners that never touch introspection.
    pub(crate) fn ensure_reflection_hashes(&mut self) {
        if self.reflection_hashes_ready {
            return;
        }
        self.reflection_hashes_ready = true;
        // Package stashes (`%main::` / `%Pkg::`) are Perl-spec, install in
        // every mode — `--compat` does not turn off the symbol table.
        self.refresh_package_stashes();
        // Everything below is stryke-only. `--compat` skips the entire block
        // so a Perl 5 script sees no extension hashes and can use `%all` /
        // `%b` / `%parameters` / `%stryke::*` etc. as ordinary user hashes.
        if crate::compat_mode() {
            return;
        }
        let builtins_map = crate::builtins::builtins_hash_map();
        let perl_compats_map = crate::builtins::perl_compats_hash_map();
        let extensions_map = crate::builtins::extensions_hash_map();
        let aliases_map = crate::builtins::aliases_hash_map();
        let descriptions_map = crate::builtins::descriptions_hash_map();
        let categories_map = crate::builtins::categories_hash_map();
        let primaries_map = crate::builtins::primaries_hash_map();
        let keywords_map = crate::builtins::keywords_hash_map();
        let operators_map = crate::builtins::operators_hash_map();
        let special_vars_map = crate::builtins::special_vars_hash_map();
        let all_map = crate::builtins::all_hash_map();
        self.scope
            .declare_hash_global_frozen("stryke::builtins", builtins_map.clone());
        self.scope
            .declare_hash_global_frozen("stryke::perl_compats", perl_compats_map.clone());
        self.scope
            .declare_hash_global_frozen("stryke::extensions", extensions_map.clone());
        self.scope
            .declare_hash_global_frozen("stryke::aliases", aliases_map.clone());
        self.scope
            .declare_hash_global_frozen("stryke::descriptions", descriptions_map.clone());
        self.scope
            .declare_hash_global_frozen("stryke::categories", categories_map.clone());
        self.scope
            .declare_hash_global_frozen("stryke::primaries", primaries_map.clone());
        self.scope
            .declare_hash_global_frozen("stryke::keywords", keywords_map.clone());
        self.scope
            .declare_hash_global_frozen("stryke::operators", operators_map.clone());
        self.scope
            .declare_hash_global_frozen("stryke::special_vars", special_vars_map.clone());
        self.scope
            .declare_hash_global_frozen("stryke::all", all_map.clone());
        // Short aliases: only declare if no user-declared hash with that name
        // exists, to avoid overwriting `my %e` etc.
        for (name, val) in [
            ("b", builtins_map),
            ("pc", perl_compats_map),
            ("e", extensions_map),
            ("a", aliases_map),
            ("d", descriptions_map),
            ("c", categories_map),
            ("p", primaries_map),
            ("k", keywords_map),
            ("o", operators_map),
            ("v", special_vars_map),
            ("all", all_map),
        ] {
            if !self.scope.any_frame_has_hash(name) {
                self.scope.declare_hash_global_frozen(name, val);
            }
        }
        // Initial install of `%parameters` (zsh-`$parameters` analogue).
        // Refreshed automatically on every read via `touch_env_hash`.
        if !self.scope.has_lexical_hash("parameters") {
            self.refresh_parameters_hash();
        }
    }

    /// Rebuild `%parameters` (zsh-`$parameters` analogue) from the current
    /// scope. Maps every live sigil-prefixed name (`$x`, `@a`, `%h`, …) to its
    /// kind string (`"scalar"`, `"array"`, `"hash"`, `"atomic_array"`,
    /// `"atomic_hash"`, `"shared_array"`, `"shared_hash"`). Installed as a
    /// frozen global hash so user code can read it but not assign into it
    /// (parallel to `%all` / `%b` / `%stryke::*`). Refreshed automatically on
    /// every `%parameters` read via the `touch_env_hash` hook, so the snapshot
    /// is always current — the user never needs to call this directly.
    pub fn refresh_parameters_hash(&mut self) {
        let pairs = self.scope.parameters_pairs();
        let mut h: indexmap::IndexMap<String, StrykeValue> =
            indexmap::IndexMap::with_capacity(pairs.len());
        for (name, kind) in pairs {
            h.insert(name, StrykeValue::string(kind.to_string()));
        }
        // declare_hash_global_frozen overwrites unconditionally, so each
        // refresh replaces the prior snapshot.
        self.scope.declare_hash_global_frozen("parameters", h);
    }

    /// Populate `%main::` / `%Foo::` package stashes with current symbol-table
    /// state so `keys %main::` and `keys %Foo::` enumerate live names. Maps
    /// each unqualified name → its kind string (`"scalar"`, `"array"`,
    /// `"hash"`, `"sub"`). Stryke has no real Perl typeglob layer; the kind
    /// string is the most useful per-symbol value we can offer.
    ///
    /// Callable repeatedly — overwrites prior stashes — so the REPL refreshes
    /// after every line and scripts can call it explicitly via the
    /// `refresh_stashes()` builtin if they want post-eval visibility.
    pub fn refresh_package_stashes(&mut self) {
        use indexmap::IndexMap;

        let mut by_pkg: std::collections::HashMap<String, IndexMap<String, StrykeValue>> =
            std::collections::HashMap::new();

        let record = |pkg: &str,
                      sym: &str,
                      kind: &str,
                      map: &mut std::collections::HashMap<
            String,
            IndexMap<String, StrykeValue>,
        >| {
            map.entry(pkg.to_string())
                .or_default()
                .insert(sym.to_string(), StrykeValue::string(kind.to_string()));
        };

        // Subs: keys like "main::foo" / "Foo::Bar::baz".
        for key in self.subs.keys() {
            if let Some(idx) = key.rfind("::") {
                let (pkg, rest) = key.split_at(idx);
                let sym = &rest[2..];
                if pkg.is_empty() || sym.is_empty() {
                    continue;
                }
                record(pkg, sym, "sub", &mut by_pkg);
            } else {
                // Bare-name sub (no package qualifier) lives in main::.
                record("main", key, "sub", &mut by_pkg);
            }
        }

        // Package-qualified scalars / arrays / hashes from every frame.
        for frame in self.scope.frames_for_introspection() {
            let (scalars, arrays, hashes) = frame;
            for name in scalars {
                if let Some(idx) = name.rfind("::") {
                    let (pkg, rest) = name.split_at(idx);
                    let sym = &rest[2..];
                    if !pkg.is_empty() && !sym.is_empty() {
                        record(pkg, sym, "scalar", &mut by_pkg);
                    }
                }
            }
            for name in arrays {
                if let Some(idx) = name.rfind("::") {
                    let (pkg, rest) = name.split_at(idx);
                    let sym = &rest[2..];
                    if !pkg.is_empty() && !sym.is_empty() {
                        record(pkg, sym, "array", &mut by_pkg);
                    }
                }
            }
            for name in hashes {
                if let Some(idx) = name.rfind("::") {
                    let (pkg, rest) = name.split_at(idx);
                    let sym = &rest[2..];
                    if !pkg.is_empty() && !sym.is_empty() {
                        record(pkg, sym, "hash", &mut by_pkg);
                    }
                }
            }
        }

        // Install each `%Pkg::` in the global frame. Lexer emits the trailing
        // `::` as part of the name, so the stash hash lives under that exact
        // key. `declare_hash_global_frozen` overwrites any prior copy.
        for (pkg, mut entries) in by_pkg {
            entries.sort_keys();
            let key = format!("{}::", pkg);
            self.scope.declare_hash_global_frozen(&key, entries);
        }
    }

    /// `overload::import` / `overload::unimport` — core stubs used by CPAN modules (e.g.
    /// `JSON::PP::Boolean`) before real `overload.pm` is modeled. Empty bodies are enough for
    /// strict subs and to satisfy `use overload ();` call sites.
    fn install_overload_pragma_stubs(&mut self) {
        let empty: Block = vec![];
        for key in ["overload::import", "overload::unimport"] {
            let name = key.to_string();
            self.subs.insert(
                name.clone(),
                Arc::new(StrykeSub {
                    name,
                    params: vec![],
                    body: empty.clone(),
                    prototype: None,
                    closure_env: None,
                    fib_like: None,
                    return_type: None,
                }),
            );
        }
    }

